import React, { useState, useEffect, useRef } from 'react';
import './OrderFlow.css';

// ===================== FUEL DATA =====================
const FUEL_PRICES = {
  Diesel: 87.71,
  Petrol: 96.72,
  LPG: 903,
  CNG: 75,
};

const FUEL_UNIT = {
  Diesel: 'litre',
  Petrol: 'litre',
  LPG: 'cylinder',
  CNG: 'kg',
};

const FUEL_MIN = {
  Diesel: 150,
  Petrol: 150,
  LPG: 10,
  CNG: 150,
};

const STATES = ['Delhi', 'Haryana', 'Uttar Pradesh', 'Rajasthan', 'Maharashtra', 'Karnataka', 'Tamil Nadu', 'Gujarat', 'Punjab', 'Telangana', 'West Bengal', 'Madhya Pradesh'];
const CITIES = {
  Delhi: ['New Delhi', 'Dwarka', 'Rohini', 'Saket', 'Lajpat Nagar'],
  Haryana: ['Gurugram', 'Faridabad', 'Sonipat', 'Panipat', 'Ambala'],
  UttarPradesh: ['Noida', 'Ghaziabad', 'Lucknow', 'Agra', 'Kanpur'],
  Maharashtra: ['Mumbai', 'Pune', 'Nagpur', 'Thane', 'Nashik'],
  Karnataka: ['Bengaluru', 'Mysuru', 'Hubli', 'Mangaluru', 'Belgaum'],
  Rajasthan: ['Jaipur', 'Jodhpur', 'Udaipur', 'Kota', 'Ajmer'],
  Gujarat: ['Ahmedabad', 'Surat', 'Vadodara', 'Rajkot', 'Bhavnagar'],
  'Tamil Nadu': ['Chennai', 'Coimbatore', 'Madurai', 'Trichy', 'Salem'],
  Punjab: ['Chandigarh', 'Ludhiana', 'Amritsar', 'Jalandhar', 'Patiala'],
  Telangana: ['Hyderabad', 'Warangal', 'Nizamabad', 'Khammam', 'Karimnagar'],
  'West Bengal': ['Kolkata', 'Howrah', 'Asansol', 'Durgapur', 'Siliguri'],
  'Madhya Pradesh': ['Bhopal', 'Indore', 'Jabalpur', 'Gwalior', 'Ujjain'],
};

const VEHICLE_TYPES = ['Diesel Generator', 'Construction Equipment', 'Fleet Vehicle', 'Industrial Boiler', 'Farm Machinery', 'Other'];

const DELIVERY_PERSON = {
  name: 'Ravi Kumar',
  phone: '+91 98765 43210',
  img: 'https://images.pexels.com/photos/6868168/pexels-photo-6868168.jpeg',
  vehicle: 'DL 01 MT 4521',
  eta: '~45 minutes',
  rating: '4.9',
};

const STEPS = ['Fuel Type', 'Quantity', 'Address', 'Delivery Time', 'Review', 'Payment'];

// ===================== VEGAAH PAYMENT COMPONENT (from travel site) =====================
const VegaahPayment = ({ amountInt, mobileNo, rentData, typeSet = 'service', onSuccess, onError }) => {
  const [isFrame, setIsFrame] = useState(false);
  const [keyGroup, setKeyGroup] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const formRef = useRef(null);

  const isValidAmount = amountInt >= 10 && amountInt <= 50000;

  useEffect(() => {
    if (amountInt && mobileNo && isValidAmount) {
      setTimeout(() => handleSubmit(), 100);
    }
  }, [amountInt, mobileNo]);

  const handleSubmit = async () => {
    if (!isValidAmount) {
      setError('Amount must be between ₹10 and ₹50,000');
      if (onError) onError('Amount must be between ₹10 and ₹50,000');
      return;
    }
    if (!mobileNo || mobileNo.length !== 10) {
      setError('Valid 10-digit mobile number required');
      if (onError) onError('Valid 10-digit mobile number required');
      return;
    }

    setIsLoading(true);
    setError('');

    try {
      const apiUrl = typeSet === 'service'
        ? 'https://chagans.com/pg1/checkoutConc'
        : 'https://chagans.com/payment/addMoneyTen';

      const res = await fetch(apiUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          authorization: '',
          latitude: '28.6139',
          longitude: '77.2090',
        },
        body: JSON.stringify({
          amount: amountInt,
          mobile: mobileNo,
          rentData: rentData,
          pgType: 'fastag',
          apiType: 'API',
        }),
      });

      const data = await res.json();
      if (data.success) {
        if (typeSet !== 'service') {
          setIsFrame(true);
          setKeyGroup(data.data);
          setTimeout(() => {
            if (formRef.current) formRef.current.submit();
          }, 500);
        } else if (typeSet === 'service' && data.data?.transactionId) {
          window.open(data.data.paymentLink?.linkUrl + data.data.transactionId, '_blank');
          if (onSuccess) onSuccess();
        } else {
          setError(data.message || 'Payment initialization failed');
          if (onError) onError(data.message);
        }
      } else {
        setError(data.message || 'Payment failed');
        if (onError) onError(data.message);
      }
    } catch (err) {
      setError('Network error. Please check your connection.');
      if (onError) onError('Network error');
    } finally {
      setIsLoading(false);
    }
  };

  if (isFrame) {
    return (
      <div className="payment-redirect">
        <form action={keyGroup?.APIURL} method="POST" ref={formRef}>
          {keyGroup && Object.entries(keyGroup)
            .filter(([key]) => key !== 'APIURL' && key !== 'mobile')
            .map(([key, value]) => (
              <input type="hidden" key={key} name={key.toUpperCase()} value={value} />
            ))}
        </form>
        <div className="redirect-spinner"></div>
        <p>Redirecting to Vegaah Secure Gateway...</p>
      </div>
    );
  }

  return (
    <div className="vegaah-payment-container">
      {error && <div className="payment-error">⚠️ {error}</div>}
      {isLoading && <div className="payment-loading">Processing payment...</div>}
      {!isFrame && !isLoading && (
        <button
          className="vegaah-pay-btn"
          onClick={handleSubmit}
          disabled={!isValidAmount || mobileNo.length !== 10}
        >
          💳 Pay ₹{amountInt.toLocaleString('en-IN')} via Vegaah
        </button>
      )}
    </div>
  );
};

// ===================== MAIN ORDER FLOW COMPONENT =====================
export default function OrderFlow({ navigate }) {
  const [step, setStep] = useState(0);
  const [fuelType, setFuelType] = useState('');
  const [vehicleType, setVehicleType] = useState('');
  const [quantity, setQuantity] = useState('');
  const [address, setAddress] = useState({
    line1: '', line2: '', state: '', city: '', pincode: '', mobile: '', name: ''
  });
  const [deliveryDate, setDeliveryDate] = useState('');
  const [deliverySlot, setDeliverySlot] = useState('');
  const [payMethod, setPayMethod] = useState('');
  const [orderPlaced, setOrderPlaced] = useState(false);
  const [errors, setErrors] = useState({});
  const [showPayment, setShowPayment] = useState(false);
  const [paymentError, setPaymentError] = useState('');

  const price = fuelType ? FUEL_PRICES[fuelType] : 0;
  const qty = parseFloat(quantity) || 0;
  const subtotal = fuelType === 'LPG' ? qty * price : qty * price;
  const deliveryFee = qty >= 500 ? 0 : 299;
  const gst = parseFloat((subtotal * 0.18).toFixed(2));
  const total = parseFloat((subtotal + deliveryFee + gst).toFixed(2));

  const today = new Date();
  const dates = Array.from({ length: 6 }, (_, i) => {
    const d = new Date(today);
    d.setDate(today.getDate() + i);
    return { label: d.toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'short' }), val: d.toISOString().split('T')[0] };
  });
  const slots = ['6 AM – 10 AM', '10 AM – 2 PM', '2 PM – 6 PM', '6 PM – 9 PM'];

  const handleUPI = () => {
    setPayMethod('upi');
    setShowPayment(true);
    setPaymentError('');
  };

  const handleCOD = () => {
    setPayMethod('cod');
    setShowPayment(false);
    setPaymentError('');
  };

  const handlePaymentError = (msg) => {
    setPaymentError(msg || 'Payment failed. Please try again.');
    setShowPayment(false);
    setPayMethod('');
  };

  const handlePaymentSuccess = () => {
    setOrderPlaced(true);
  };

  const validate = (s) => {
    if (s === 0 && !fuelType) {
      setErrors({ fuelType: 'Please select fuel type' });
      return false;
    }
    if (s === 1) {
      if (!vehicleType) {
        setErrors({ vehicleType: 'Select vehicle/asset type' });
        return false;
      }
      if (!quantity || qty < FUEL_MIN[fuelType]) {
        setErrors({ quantity: `Minimum order is ${FUEL_MIN[fuelType]} ${FUEL_UNIT[fuelType]}s` });
        return false;
      }
    }
    if (s === 2) {
      const e = {};
      if (!address.name) e.name = 'Name required';
      if (!address.line1) e.line1 = 'Address required';
      if (!address.state) e.state = 'Select state';
      if (!address.city) e.city = 'Select city';
      if (!address.pincode || address.pincode.length !== 6) e.pincode = 'Valid 6-digit pincode required';
      if (!address.mobile || address.mobile.length !== 10) e.mobile = 'Valid 10-digit mobile required';
      if (Object.keys(e).length) {
        setErrors(e);
        return false;
      }
    }
    if (s === 3) {
      if (!deliveryDate || !deliverySlot) {
        setErrors({ slot: 'Select date and time slot' });
        return false;
      }
    }
    if (s === 5) {
      if (!payMethod) {
        setErrors({ pay: 'Select payment method' });
        return false;
      }
    }
    setErrors({});
    return true;
  };

  const next = () => {
    if (validate(step)) setStep(s => s + 1);
  };

  const back = () => {
    setStep(s => s - 1);
    setErrors({});
  };

  const placeOrder = () => {
    if (!validate(5)) return;
    if (payMethod === 'cod') setOrderPlaced(true);
  };

  // Build rentData for Vegaah (similar to travel booking structure)
  const rentDataForPayment = {
    orderId: `FD${Date.now().toString().slice(-8)}`,
    fuelType,
    vehicleType,
    quantity: qty,
    unit: FUEL_UNIT[fuelType],
    address,
    deliveryDate,
    deliverySlot,
    subtotal,
    deliveryFee,
    gst,
    total,
  };

  if (orderPlaced) {
    return (
      <div className="fdo-confirm">
        <div className="fdo-confirm-card">
          <div className="fdo-confirm-check">✅</div>
          <h2>Order Confirmed!</h2>
          <p className="fdo-confirm-sub">Your fuel delivery is on its way.</p>
          <div className="fdo-order-id">Order ID: <strong>FD{Date.now().toString().slice(-8)}</strong></div>
          <div className="fdo-driver-card">
            <img src={DELIVERY_PERSON.img} alt="driver" className="fdo-driver-img" />
            <div className="fdo-driver-info">
              <div className="fdo-driver-name">{DELIVERY_PERSON.name}</div>
              <div className="fdo-driver-sub">Your Delivery Executive</div>
              <div className="fdo-driver-detail">⭐ {DELIVERY_PERSON.rating} rating | 🚚 {DELIVERY_PERSON.vehicle}</div>
              <div className="fdo-driver-detail">⏱️ ETA: <strong>{DELIVERY_PERSON.eta}</strong></div>
            </div>
            <a href={`tel:${DELIVERY_PERSON.phone}`} className="fdo-call-btn">📞 {DELIVERY_PERSON.phone}</a>
          </div>
          <div className="fdo-confirm-summary">
            <div className="fdo-cs-row"><span>{fuelType}</span><span>{qty} {FUEL_UNIT[fuelType]}s</span></div>
            <div className="fdo-cs-row"><span>Delivery to</span><span>{address.city}, {address.state}</span></div>
            <div className="fdo-cs-row"><span>Slot</span><span>{deliveryDate} · {deliverySlot}</span></div>
            <div className="fdo-cs-row fdo-cs-total"><span>Total Paid</span><span>₹{total.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span></div>
          </div>
          <div className="fdo-tanker-msg">
            <img src="https://images.unsplash.com/photo-1601584115197-04ecc0da31d7?w=400&q=80" alt="tanker" />
            <p>🚛 Your FuelDrop tanker has left our depot. You'll receive live tracking updates on your mobile.</p>
          </div>
          <button className="fdo-home-btn" onClick={() => navigate('home')}>← Back to Home</button>
        </div>
      </div>
    );
  }

  return (
    <div className="fdo-page">
      {/* Progress Bar */}
      <div className="fdo-progress-wrap">
        <div className="fdo-progress-bar">
          {STEPS.map((s, i) => (
            <div key={i} className={`fdo-progress-step${i <= step ? ' fdo-prog-done' : ''}${i === step ? ' fdo-prog-active' : ''}`}>
              <div className="fdo-prog-circle">{i < step ? '✓' : i + 1}</div>
              <span>{s}</span>
            </div>
          ))}
        </div>
      </div>

      <div className="fdo-content">
        <div className="fdo-main">
          {/* STEP 0: Fuel Type */}
          {step === 0 && (
            <div className="fuel-wrapper">
              <div className="wrapper-head"><span className="head-badge">⛽ FUEL</span><h6 className="head-title">Choose fuel type</h6></div>
              <div className="wrapper-body">
                {Object.keys(FUEL_PRICES).map((fuel) => (
                  <button key={fuel} className={`wrapper-item ${fuelType === fuel ? 'wrapper-item-active' : ''}`} onClick={() => setFuelType(fuel)}>
                    <div className="item-content">
                      <span className="item-icon">{fuel === 'Diesel' ? '⛽' : fuel === 'Petrol' ? '⛽' : fuel === 'LPG' ? '🔥' : '⚡'}</span>
                      <span className="item-name">{fuel}</span>
                      <span className="item-price">₹{FUEL_PRICES[fuel]}</span>
                    </div>
                  </button>
                ))}
              </div>
              {errors.fuelType && <div className="wrapper-foot error"><span>●</span><span>{errors.fuelType}</span></div>}
            </div>
          )}

          {/* STEP 1: Quantity & Asset */}
          {step === 1 && (
            <div className="fdo-step">
              <h2>Select Quantity & Asset</h2>
              <p className="fdo-step-sub">Minimum order: <strong>{FUEL_MIN[fuelType]} {FUEL_UNIT[fuelType]}s</strong> of {fuelType}</p>
              <div className="fdo-field">
                <label>Vehicle / Asset Type *</label>
                <div className="fdo-vehicle-grid">
                  {VEHICLE_TYPES.map(v => (
                    <button key={v} className={`fdo-vehicle-btn${vehicleType === v ? ' fdo-v-selected' : ''}`} onClick={() => { setVehicleType(v); setErrors({}); }}>
                      {v}
                    </button>
                  ))}
                </div>
                {errors.vehicleType && <div className="fdo-error">{errors.vehicleType}</div>}
              </div>
              <div className="fdo-field">
                <label>Quantity ({FUEL_UNIT[fuelType]}s) *</label>
                <div className="fdo-qty-row">
                  <input type="number" min={FUEL_MIN[fuelType]} placeholder={`e.g. ${FUEL_MIN[fuelType]}`} value={quantity} onChange={e => { setQuantity(e.target.value); setErrors({}); }} />
                  <div className="fdo-qty-unit">{FUEL_UNIT[fuelType]}s</div>
                </div>
                {errors.quantity && <div className="fdo-error">{errors.quantity}</div>}
              </div>
              {quantity && qty >= FUEL_MIN[fuelType] && (
                <div className="fdo-price-preview">
                  <div className="fdo-pp-row"><span>{qty} {FUEL_UNIT[fuelType]}s × ₹{price}</span><span>₹{subtotal.toFixed(2)}</span></div>
                  <div className="fdo-pp-row"><span>Delivery fee</span><span>{deliveryFee === 0 ? <span className="fdo-free">FREE</span> : `₹${deliveryFee}`}</span></div>
                  <div className="fdo-pp-row"><span>18% GST</span><span>₹{gst}</span></div>
                  <div className="fdo-pp-total"><span>Estimated Total</span><span>₹{total.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</span></div>
                </div>
              )}
            </div>
          )}

          {/* STEP 2: Address */}
          {step === 2 && (
            <div className="fdo-step">
              <h2>Delivery Address</h2>
              <p className="fdo-step-sub">Where should we deliver your fuel?</p>
              <div className="fdo-form-grid">
                <div className="fdo-field fdo-full"><label>Full Name / Company Name *</label><input placeholder="Ramesh Kumar / ABC Industries" value={address.name} onChange={e => setAddress({ ...address, name: e.target.value })} />{errors.name && <span className="fdo-error">{errors.name}</span>}</div>
                <div className="fdo-field fdo-full"><label>Address Line 1 *</label><input placeholder="House/Flat No., Street, Colony" value={address.line1} onChange={e => setAddress({ ...address, line1: e.target.value })} />{errors.line1 && <span className="fdo-error">{errors.line1}</span>}</div>
                <div className="fdo-field fdo-full"><label>Address Line 2 (Optional)</label><input placeholder="Landmark, Near ..." value={address.line2} onChange={e => setAddress({ ...address, line2: e.target.value })} /></div>
                <div className="fdo-field"><label>State *</label><select value={address.state} onChange={e => setAddress({ ...address, state: e.target.value, city: '' })}><option value="">Select State</option>{STATES.map(s => <option key={s}>{s}</option>)}</select>{errors.state && <span className="fdo-error">{errors.state}</span>}</div>
                <div className="fdo-field"><label>City *</label><select value={address.city} onChange={e => setAddress({ ...address, city: e.target.value })}><option value="">Select City</option>{(CITIES[address.state] || []).map(c => <option key={c}>{c}</option>)}</select>{errors.city && <span className="fdo-error">{errors.city}</span>}</div>
                <div className="fdo-field"><label>PIN Code *</label><input maxLength={6} placeholder="110017" value={address.pincode} onChange={e => setAddress({ ...address, pincode: e.target.value.replace(/\D/g, '') })} />{errors.pincode && <span className="fdo-error">{errors.pincode}</span>}</div>
                <div className="fdo-field"><label>Mobile Number *</label><div className="fdo-mobile-row"><span className="fdo-code">+91</span><input maxLength={10} placeholder="9876543210" value={address.mobile} onChange={e => setAddress({ ...address, mobile: e.target.value.replace(/\D/g, '') })} /></div>{errors.mobile && <span className="fdo-error">{errors.mobile}</span>}</div>
              </div>
            </div>
          )}

          {/* STEP 3: Delivery Time */}
          {step === 3 && (
            <div className="fdo-step">
              <h2>Choose Delivery Time</h2>
              <p className="fdo-step-sub">Pick a date and time slot for your delivery.</p>
              <div className="fdo-dates">
                {dates.map((d, i) => <button key={i} className={`fdo-date-btn${deliveryDate === d.val ? ' fdo-date-sel' : ''}`} onClick={() => { setDeliveryDate(d.val); setErrors({}); }}>{d.label}</button>)}
              </div>
              <div className="fdo-slots">
                <h4>Available Time Slots</h4>
                <div className="fdo-slot-grid">
                  {slots.map((s, i) => <button key={i} className={`fdo-slot-btn${deliverySlot === s ? ' fdo-slot-sel' : ''}`} onClick={() => { setDeliverySlot(s); setErrors({}); }}><i className="fa fa-clock"></i> {s}</button>)}
                </div>
              </div>
              {errors.slot && <div className="fdo-error">{errors.slot}</div>}
            </div>
          )}

          {/* STEP 4: Review */}
          {step === 4 && (
            <div className="fdo-step">
              <h2>Review Your Order</h2>
              <p className="fdo-step-sub">Please verify all details before proceeding to payment.</p>
              <div className="fdo-review-grid">
                <div className="fdo-review-card"><h4><i className="fa fa-gas-pump"></i> Fuel Details</h4><div className="fdo-rv-row"><span>Fuel Type</span><strong>{fuelType}</strong></div><div className="fdo-rv-row"><span>Asset Type</span><strong>{vehicleType}</strong></div><div className="fdo-rv-row"><span>Quantity</span><strong>{qty} {FUEL_UNIT[fuelType]}s</strong></div><div className="fdo-rv-row"><span>Rate</span><strong>₹{price}/{FUEL_UNIT[fuelType]}</strong></div></div>
                <div className="fdo-review-card"><h4><i className="fa fa-map-marker-alt"></i> Delivery Address</h4><div className="fdo-rv-row"><span>Name</span><strong>{address.name}</strong></div><div className="fdo-rv-row"><span>Address</span><strong>{address.line1}{address.line2 ? ', ' + address.line2 : ''}</strong></div><div className="fdo-rv-row"><span>City</span><strong>{address.city}, {address.state}</strong></div><div className="fdo-rv-row"><span>PIN</span><strong>{address.pincode}</strong></div><div className="fdo-rv-row"><span>Mobile</span><strong>+91 {address.mobile}</strong></div></div>
                <div className="fdo-review-card"><h4><i className="fa fa-clock"></i> Delivery Schedule</h4><div className="fdo-rv-row"><span>Date</span><strong>{new Date(deliveryDate + 'T00:00:00').toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long' })}</strong></div><div className="fdo-rv-row"><span>Time Slot</span><strong>{deliverySlot}</strong></div></div>
                <div className="fdo-review-card fdo-review-bill"><h4><i className="fa fa-receipt"></i> Bill Summary</h4><div className="fdo-rv-row"><span>{fuelType} × {qty} {FUEL_UNIT[fuelType]}s</span><strong>₹{subtotal.toFixed(2)}</strong></div><div className="fdo-rv-row"><span>Delivery Fee</span><strong>{deliveryFee === 0 ? '₹0 (FREE)' : `₹${deliveryFee}`}</strong></div><div className="fdo-rv-row"><span>18% GST</span><strong>₹{gst}</strong></div><div className="fdo-rv-total"><span>TOTAL</span><strong>₹{total.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</strong></div></div>
              </div>
            </div>
          )}

          {/* STEP 5: Payment – with Vegaah Gateway integrated */}
          {step === 5 && (
            <div className="fdo-step">
              <h2>Payment</h2>
              <p className="fdo-step-sub">Total payable: <strong style={{ color: '#16a34a', fontSize: '20px' }}>₹{total.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</strong></p>

              <div className="fdo-pay-methods">
                <button className={`fdo-pay-card${payMethod === 'cod' ? ' fdo-pay-sel' : ''}`} onClick={handleCOD}>
                  <div className="fdo-pay-icon">💵</div>
                  <div className="fdo-pay-text"><strong>Cash on Delivery</strong><span>Pay in cash when fuel arrives</span></div>
                  <div className={`fdo-pay-radio${payMethod === 'cod' ? ' fdo-pay-r-sel' : ''}`}></div>
                </button>
                <button className={`fdo-pay-card${payMethod === 'upi' ? ' fdo-pay-sel' : ''}`} onClick={handleUPI}>
                  <div className="fdo-pay-icon">📱</div>
                  <div className="fdo-pay-text"><strong>UPI Payment</strong><span>Pay via GPay, PhonePe, BHIM (Vegaah Gateway)</span></div>
                  <div className={`fdo-pay-radio${payMethod === 'upi' ? ' fdo-pay-r-sel' : ''}`}></div>
                </button>
              </div>

              {showPayment && (
                <VegaahPayment
                  amountInt={total}
                  mobileNo={address.mobile}
                  rentData={rentDataForPayment}
                  typeSet="service"
                  onSuccess={handlePaymentSuccess}
                  onError={handlePaymentError}
                />
              )}

              {paymentError && <div className="fdo-error" style={{ marginTop: '15px' }}>{paymentError}</div>}
              {errors.pay && !payMethod && <div className="fdo-error" style={{ marginTop: '15px' }}>{errors.pay}</div>}
            </div>
          )}

          {/* Navigation Buttons */}
          <div className="fdo-nav-btns">
            {step > 0 && <button className="fdo-back-btn" onClick={back}><i className="fa fa-arrow-left"></i> Back</button>}
            {step < 5 && <button className="fdo-next-btn" onClick={next}>Continue <i className="fa fa-arrow-right"></i></button>}
            {step === 5 && payMethod === 'cod' && <button className="fdo-place-btn" onClick={placeOrder}><i className="fa fa-bolt"></i> Place Order · ₹{total.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</button>}
          </div>
        </div>

        {/* Order Summary Sidebar */}
        {step > 0 && (
          <div className="fdo-sidebar">
            <h3>Order Summary</h3>
            {fuelType && <div className="fdo-sb-row"><span>Fuel</span><strong>{fuelType}</strong></div>}
            {vehicleType && <div className="fdo-sb-row"><span>Asset</span><strong>{vehicleType}</strong></div>}
            {qty > 0 && <div className="fdo-sb-row"><span>Quantity</span><strong>{qty} {FUEL_UNIT[fuelType]}s</strong></div>}
            {qty >= FUEL_MIN[fuelType] && (
              <>
                <div className="fdo-sb-row"><span>Subtotal</span><strong>₹{subtotal.toFixed(2)}</strong></div>
                <div className="fdo-sb-row"><span>Delivery</span><strong>{deliveryFee === 0 ? 'FREE' : `₹${deliveryFee}`}</strong></div>
                <div className="fdo-sb-row"><span>18% GST</span><strong>₹{gst}</strong></div>
                <div className="fdo-sb-total"><span>Total</span><strong>₹{total.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</strong></div>
              </>
            )}
            {address.city && <div className="fdo-sb-row fdo-sb-addr"><span>To</span><strong>{address.city}, {address.state} {address.pincode}</strong></div>}
            {deliverySlot && <div className="fdo-sb-row"><span>Slot</span><strong>{deliverySlot}</strong></div>}
            <div className="fdo-sb-badge"><i className="fa fa-shield-alt"></i> Secure & verified delivery</div>
          </div>
        )}
      </div>
    </div>
  );
}
